// Scrape a single label-series page on 78discography.com (the Online
// 78 rpm Discographical Project — Steven Abrams / Tyrone Settlemier).
//
//   node scripts/parse-abrams-label.mjs <slug> <label-name> [discogs-label-id]
//
//   <slug> is the .htm filename without extension, e.g. "Aladdin3000".
//   <label-name> is the canonical label name we store, e.g. "Aladdin".
//
// Every page is an HTML table generated by Excel's Internet Assistant
// with these columns:
//   Label: | Artist: | Tune: | MX: | Xref: | Ctrl: | Date: | Comp:
// Rows are A/B-side pairs — same catno appears twice in succession,
// alternating sides. We assign A/B/C… in order of appearance per catno.
//
// Output JSON shape matches POST /api/admin/external-discography/import:
//   { label, labelId, source: "78discography.com", rows: [...] }

const SLUG     = process.argv[2];
const LABEL    = process.argv[3];
const LABEL_ID = process.argv[4] ? Number(process.argv[4]) : null;
if (!SLUG || !LABEL) {
  console.error("usage: node parse-abrams-label.mjs <slug> <label-name> [discogs-label-id]");
  process.exit(1);
}

const URL = `https://www.78discography.com/${SLUG}.htm`;
const UA  = "SeaDisco-archival/1.0 (+https://seadisco.com, kylejester@gmail.com)";

const res = await fetch(URL, { headers: { "User-Agent": UA } });
if (!res.ok) {
  console.error(`fetch failed: ${URL} → ${res.status}`);
  process.exit(2);
}
const html = await res.text();

// Iterate every <tr>...</tr> and pick the ones with 8 <td> cells.
// Some pages have extra rows for headers / banners / ads; the cell
// count is the easiest discriminator.
const trRe = /<tr>([\s\S]*?)<\/tr>/gi;
const tdRe = /<td[^>]*>([\s\S]*?)<\/td>/gi;

function decode(s) {
  return String(s ?? "")
    .replace(/&amp;/g,  "&")
    .replace(/&lt;/g,   "<")
    .replace(/&gt;/g,   ">")
    .replace(/&quot;/g, '"')
    .replace(/&apos;/g, "'")
    .replace(/&nbsp;/g, " ")
    .replace(/<[^>]+>/g, "")    // strip any inline tags (B, FONT, BR)
    .replace(/\s+/g, " ")
    .trim();
}

function dashToNull(v) {
  if (!v || v === "-" || v === "?" || v === "n/a") return null;
  return v;
}

function parseYear(dateStr) {
  if (!dateStr) return null;
  // Match M/D/YY or M/D/YYYY anywhere in the cell.
  const m = dateStr.match(/(\d{1,2})\/(\d{1,2})\/(\d{2}|\d{4})/);
  if (!m) {
    // Fallback: bare year
    const y = dateStr.match(/\b(19\d{2}|20\d{2})\b/);
    return y ? Number(y[1]) : null;
  }
  const y = Number(m[3]);
  if (y < 100) return y < 30 ? 2000 + y : 1900 + y;  // 30 cutoff is safe for pre-70s data
  return y;
}

const sideCounter = new Map();
function nextSide(catno) {
  const n = (sideCounter.get(catno) ?? 0) + 1;
  sideCounter.set(catno, n);
  return String.fromCharCode(64 + n);  // 1→A, 2→B
}

const rows = [];
let trMatch;
while ((trMatch = trRe.exec(html)) !== null) {
  const inner = trMatch[1];
  const cells = [];
  let tdMatch;
  while ((tdMatch = tdRe.exec(inner)) !== null) {
    cells.push(decode(tdMatch[1]));
  }
  if (cells.length !== 8) continue;
  // Skip header row — first cell is "Label:" or similar
  if (/^(label|cat#?|catalog)\b:?$/i.test(cells[0])) continue;
  const catno = cells[0];
  if (!/^\d/.test(catno)) continue;   // require numeric leader
  rows.push({
    catno,
    side:     nextSide(catno),
    artist:   dashToNull(cells[1]),
    title:    dashToNull(cells[2]),
    matrix:   dashToNull(cells[3]),
    xref:     dashToNull(cells[4]),
    loc:      dashToNull(cells[5]),
    year:     parseYear(cells[6]),
    composer: dashToNull(cells[7]),
  });
}

const out = {
  label:   LABEL,
  labelId: Number.isFinite(LABEL_ID) ? LABEL_ID : null,
  source:  "78discography.com",
  rows,
};

process.stdout.write(JSON.stringify(out, null, 2));
process.stderr.write(`[abrams:${SLUG}] parsed ${rows.length} rows across ${sideCounter.size} catnos\n`);
